insert into public.ordenes_servicio (numero,reclamo_numero,establecimiento_id,zona,rubro,tarea,prioridad,estado,fecha_envio,fecha_finalizacion,monto,presupuesto,created_at,updated_at)
select numero, nullif(reclamo_numero,''), establecimiento_id, zona, rubro, tarea, prioridad, estado, fecha_envio, fecha_finalizacion, monto, presupuesto, now(), now() from carga
on conflict (numero) do update set
  reclamo_numero = excluded.reclamo_numero,
  establecimiento_id = excluded.establecimiento_id,
  zona = excluded.zona,
  rubro = excluded.rubro,
  tarea = excluded.tarea,
  prioridad = excluded.prioridad,
  estado = excluded.estado,
  fecha_envio = excluded.fecha_envio,
  fecha_finalizacion = excluded.fecha_finalizacion,
  monto = excluded.monto,
  presupuesto = excluded.presupuesto,
  updated_at = now();

-- Verificacion esperada de ESTA carga: zona 8 = 45, zona 10 = 98
select zona, count(*) as ordenes_cargadas
from public.ordenes_servicio
where zona in (8,10) and numero like ('Z' || zona || '-%')
group by zona
order by zona;

